import React, {useEffect, useMemo, useRef, useState} from 'react';
import {Alert, Button, SafeAreaView, Text, View} from 'react-native';
import * as Linking from 'expo-linking';

const OAUTH = {
  authorizationEndpoint: 'https://your-auth-server.example.com/oauth/authorize',
  tokenEndpoint: 'https://your-auth-server.example.com/oauth/token',
  redirectUri: Linking.createURL('oauthredirect'),
  clientId: 'mobile_app_client_123',
  scope: 'openid profile email',
};

function buildAuthorizeUrl(state) {
  const params = new URLSearchParams({
    response_type: 'code',
    client_id: OAUTH.clientId,
    redirect_uri: OAUTH.redirectUri,
    scope: OAUTH.scope,
    state,
  });
  return `${OAUTH.authorizationEndpoint}?${params.toString()}`;
}

async function exchangeCodeForToken(code, codeVerifier) {
  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    client_id: OAUTH.clientId,
    code,
    redirect_uri: OAUTH.redirectUri,
    code_verifier: codeVerifier,
  });

  const res = await fetch(OAUTH.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Accept: 'application/json',
    },
    body: body.toString(),
  });

  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Token exchange failed: ${res.status} ${text}`);
  }

  return res.json();
}

function randomString(length = 32) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let out = '';
  for (let i = 0; i < length; i += 1) {
    out += chars[Math.floor(Math.random() * chars.length)];
  }
  return out;
}

export default function App() {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);
  const [authCode, setAuthCode] = useState(null);
  const [loading, setLoading] = useState(false);
  const stateRef = useRef('');
  const codeVerifierRef = useRef('');

  const redirectUri = useMemo(() => OAUTH.redirectUri, []);

  useEffect(() => {
    const onUrl = async ({url}) => {
      try {
        const parsed = Linking.parse(url);
        const code = parsed?.queryParams?.code;
        const state = parsed?.queryParams?.state;

        if (!code) return;
        if (!state || state !== stateRef.current) {
          Alert.alert('OAuth Error', 'Invalid state received.');
          return;
        }

        setAuthCode(code);
        setLoading(true);
        const tokenResponse = await exchangeCodeForToken(code, codeVerifierRef.current);

        setAccessToken(tokenResponse.access_token || null);
        setRefreshToken(tokenResponse.refresh_token || null);
      } catch (e) {
        Alert.alert('OAuth Error', e.message || 'Unknown error');
      } finally {
        setLoading(false);
      }
    };

    const sub = Linking.addEventListener('url', onUrl);

    Linking.getInitialURL().then((url) => {
      if (url) onUrl({url});
    });

    return () => sub.remove();
  }, []);

  const signIn = async () => {
    try {
      setLoading(true);
      const state = randomString(24);
      const codeVerifier = randomString(64);
      stateRef.current = state;
      codeVerifierRef.current = codeVerifier;

      const authUrl = buildAuthorizeUrl(state);
      await Linking.openURL(authUrl);
    } catch (e) {
      Alert.alert('Sign In Error', e.message || 'Unable to start sign-in');
      setLoading(false);
    }
  };

  const signOut = () => {
    setAccessToken(null);
    setRefreshToken(null);
    setAuthCode(null);
    stateRef.current = '';
    codeVerifierRef.current = '';
  };

  return (
    <SafeAreaView style={{flex: 1, justifyContent: 'center', alignItems: 'center', padding: 24}}>
      <View style={{gap: 12, width: '100%'}}>
        <Text style={{fontSize: 22, fontWeight: '700', textAlign: 'center'}}>OAuth 2.0 Mobile App</Text>
        <Text style={{textAlign: 'center'}}>Redirect URI: {redirectUri}</Text>
        <Text selectable>Authorization Code: {authCode || 'None'}</Text>
        <Text selectable>Access Token: {accessToken || 'None'}</Text>
        <Text selectable>Refresh Token: {refreshToken || 'None'}</Text>
        <Button title={loading ? 'Working...' : 'Sign In with OAuth'} onPress={signIn} disabled={loading} />
        <Button title="Sign Out" onPress={signOut} />
      </View>
    </SafeAreaView>
  );
}